export function numberToWordsSpanish(n: number): string {
    const unidades = ['', 'UN', 'DOS', 'TRES', 'CUATRO', 'CINCO', 'SEIS', 'SIETE', 'OCHO', 'NUEVE'];
    const decenas = ['', 'DIEZ', 'VEINTE', 'TREINTA', 'CUARENTA', 'CINCUENTA', 'SESENTA', 'SETENTA', 'OCHENTA', 'NOVENTA'];
    const especiales = ['DIEZ', 'ONCE', 'DOCE', 'TRECE', 'CATORCE', 'QUINCE', 'DIECISEIS', 'DIECISIETE', 'DIECIOCHO', 'DIECINUEVE'];
    const centenas = ['', 'CIENTO', 'DOSCIENTOS', 'TRESCIENTOS', 'CUATROCIENTOS', 'QUINIENTOS', 'SEISCIENTOS', 'SETECIENTOS', 'OCHOCIENTOS', 'NOVECIENTOS'];

    const convertirMenorA1000 = (num: number): string => {
        if (num === 0) return '';
        if (num === 100) return 'CIEN';
        
        let res = '';
        if (num >= 100) {
            res += centenas[Math.floor(num / 100)] + ' ';
            num %= 100;
        }
        
        if (num >= 10 && num <= 19) {
            res += especiales[num - 10];
        } else {
            if (num >= 20) {
                if (num === 20) return res + 'VEINTE';
                if (num < 30) {
                    res += 'VEINTI' + unidades[num - 20];
                    num = 0;
                } else {
                    res += decenas[Math.floor(num / 10)];
                    num %= 10;
                    if (num > 0) res += ' Y ';
                }
            }
            if (num > 0) {
                res += unidades[num];
            }
        }
        return res.trim();
    };

    if (n === 0) return 'CERO PESOS CON 00/100';
    
    let integerPart = Math.floor(n);
    let decimalPart = Math.round((n - integerPart) * 100);
    
    let res = '';
    
    if (integerPart >= 1000000) {
        let millones = Math.floor(integerPart / 1000000);
        res += (millones === 1 ? 'UN MILLON' : convertirMenorA1000(millones) + ' MILLONES') + ' ';
        integerPart %= 1000000;
    }
    
    if (integerPart >= 1000) {
        let miles = Math.floor(integerPart / 1000);
        res += (miles === 1 ? 'MIL' : convertirMenorA1000(miles) + ' MIL') + ' ';
        integerPart %= 1000;
    }
    
    res += convertirMenorA1000(integerPart);
    
    const centavos = decimalPart.toString().padStart(2, '0');
    return `${res.trim()} PESOS CON ${centavos}/100`.toUpperCase();
}

export const generateQuotePDF = (quote: any, supplier: any, items: any[] = [], center?: any, logoBase64?: string) => {
  const doc = new jsPDF();
  const centerName = center?.name || "Gestify RD";
  const centerCode = center?.codigo_no || "06907";

  try {
    doc.addImage(logoBase64 || MINERD_LOGO, 'PNG', 85, 2, LOGO_W, LOGO_H);
  } catch (e) {
    console.error("Error adding logo:", e);
  }

  doc.setFontSize(9);
  doc.text(center?.regional ? `DIRECCIÓN REGIONAL ${center.regional.toUpperCase()}` : "DIRECCIÓN REGIONAL 12 HIGÜEY", 105, 55, { align: "center" });
  doc.text(center?.district ? `DIRECCIÓN DISTRITAL ${center.district.toUpperCase()}` : "DIRECCIÓN DISTRITAL 12-01, HIGÜEY", 105, 60, { align: "center" });

  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text("MANTENIMIENTO ESCOLAR", 105, 72, { align: "center" });
  doc.text(quote.type === 'labor' ? "Cotización de Mano de Obra Especializada" : "Cotización de Materiales", 105, 79, { align: "center" });

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  const centerText = `Nombre del Centro: ${centerName}`;
  const centerLines = doc.splitTextToSize(centerText, 170);
  doc.text(centerLines, 20, 95);

  const servicesY = 105 + (centerLines.length * 6);
  doc.text("SERVICIOS COTIZADOS", 105, servicesY, { align: "center" });

  const tableStartY = servicesY + 5;
  const tableBody = (items && items.length > 0)
    ? items.map((item, index) => [
      (index + 1).toString(),
      item.name || item.description || 'N/A',
      (item.quantity || 1).toString(),
      formatCurrency(item.unit_price || 0),
      formatCurrency((item.quantity || 1) * (item.unit_price || 0))
    ])
    : [['1', quote.description || 'Reparación / Mantenimiento', '1', formatCurrency(quote.total_amount), formatCurrency(quote.total_amount)]];

  autoTable(doc, {
    startY: tableStartY,
    head: [['No.', 'Descripción', 'Cantidad', 'Precio Unidad', 'Total, RD$']],
    body: tableBody,
    foot: [
      ['', '', '', 'Sub - Total', formatCurrency(quote.subtotal)],
      ['', '', '', 'Itebis', formatCurrency(quote.itbis)],
      ['', '', '', 'Total', formatCurrency(quote.total_amount)]
    ],
    theme: 'grid',
    headStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' },
    footStyles: { fillColor: [255, 255, 255], textColor: [0, 0, 0], fontStyle: 'bold' }
  });

  const finalY = (doc as any).lastAutoTable.finalY + 15;
  const supplierText = `Nombre del Oferente: ${supplier.name}`;
  const supplierLines = doc.splitTextToSize(supplierText, 170);
  
  // Check page break for supplier info and signature
  const pageHeight = doc.internal.pageSize.height;
  let currentY = finalY;
  
  if (currentY + (supplierLines.length * 7) + 30 > pageHeight - 20) {
    doc.addPage();
    currentY = 20;
  }

  doc.text(supplierLines, 20, currentY);
  currentY += (supplierLines.length * 7);
  
  doc.text(`Cédula No. ${supplier.rnc}`, 20, currentY);
  doc.text(`Teléfono: ${supplier.phone || 'N/A'}`, 120, currentY);
  currentY += 7;
  doc.text(`N. Cotización: ${quote.quote_number || quote.id}`, 20, currentY);
  doc.text(`Fecha: ${formatDate(quote.created_at)}`, 120, currentY);

  doc.text("Firma del oferente__________________________", 60, currentY + 20);

  doc.save(`Cotizacion_${quote.quote_number || quote.id}.pdf`);
};

