export const generateCashBookReportPDF = (data: any[], startDate: string, endDate: string, center?: any) => {
  const doc = new jsPDF({
    orientation: 'landscape',
    unit: 'mm',
    format: 'a4'
  });
  const centerName = center?.name || "GESTIFY RD";

  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  try {
    doc.addImage(MINERD_LOGO, 'PNG', 128.5, 5, LOGO_W, LOGO_H);
  } catch (e) {}
  doc.text(centerName.toUpperCase(), 148.5, 40.0, { align: "center" });
  doc.setFontSize(14);
  doc.text("LIBRO DE INGRESOS, EGRESOS Y DISPONIBILIDAD (CAJA)", 148.5, 47.0, { align: "center" });
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  if (startDate && endDate) {
    doc.text(`Periodo: ${formatDate(startDate)} al ${formatDate(endDate)}`, 148.5, 53.0, { align: "center" });
  }

  const totalIncome = data.reduce((sum, row) => sum + (parseFloat(row.income) || 0), 0);
  const totalExpense = data.reduce((sum, row) => sum + (parseFloat(row.expense) || 0), 0);
  const totalISR = data.reduce((sum, row) => sum + (parseFloat(row.retention_isr) || 0), 0);
  const totalITBIS = data.reduce((sum, row) => sum + (parseFloat(row.retention_itbis) || 0), 0);

  const tableBody = data.map(row => [
    formatDate(row.date),
    row.reference_no || '',
    row.beneficiary || '',
    row.concept || '',
    formatCurrency(row.income),
    formatCurrency(row.expense),
    formatCurrency(row.balance),
    formatCurrency(row.retention_isr),
    formatCurrency(row.retention_itbis)
  ]);

  autoTable(doc, {
    startY: 60.0,
    head: [['FECHA', 'REF/CHQ', 'BENEFICIARIO', 'CONCEPTO', 'INGRESOS', 'EGRESOS', 'DISPONIBLE', 'RET. ISR', 'RET. ITBIS']],
    body: tableBody,
    foot: [[
      '', '', '', 'TOTALES RD$',
      formatCurrency(totalIncome),
      formatCurrency(totalExpense),
      '',
      formatCurrency(totalISR),
      formatCurrency(totalITBIS)
    ]],
    theme: 'grid',
    showFoot: 'lastPage',
    styles: { fontSize: 7, cellPadding: 2 },
    headStyles: { fillColor: [15, 23, 42], textColor: [255, 255, 255], fontStyle: 'bold' },
    footStyles: { fillColor: [241, 245, 249], textColor: [15, 23, 42], fontStyle: 'bold' },
    columnStyles: {
      4: { halign: 'right' },
      5: { halign: 'right' },
      6: { halign: 'right' },
      7: { halign: 'right' },
      8: { halign: 'right' }
    }
  });

  doc.save(`Libro_Caja_${startDate}_${endDate}.pdf`);
};

